async function run(input, ctx) {
  const review = JSON.parse(input.review_json);
  await ctx.tables.insert('pr_reviews', {
    pr_url:         input.pr_url,
    pr_title:       input.pr_title || '',
    author:         input.author || '',
    verdict:        review.verdict || 'NEEDS_DISCUSSION',
    summary:        review.summary || '',
    bug_count:      (review.bugs || []).length,
    security_count: (review.security || []).length,
    style_count:    (review.style || []).length,
    full_review:    input.review_json,
    status:         'COMPLETE'
  });
  return { saved: true };
}
